import * as echarts from 'echarts';
export default {
  name: "Home",
  data() {
    return {};
  },
  mounted() {
    //页面元素加载完成后执行
    var chartDom = document.getElementById('main');
    var myChart = echarts.init(chartDom);
    var pieDom = document.getElementById('pie');
    var piChart = echarts.init(pieDom);
    var option, pie;
    option = {
      xAxis: {
        type: 'category',
        data: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']
      },
      yAxis: {
        type: 'value'
      },
      series: [{
        data: [150, 230, 224, 218, 135, 147, 260],
        type: 'line'
      }]
    };
    this.request.get("/echarts/example").then(res => {
      //填空
      option.xAxis = res.data.x;
      option.series[0].data = res.data.x;
      option.series[1].data = res.data.y;
      //数据准备完毕，开始绘制图表
      myChart.setOption(option);
    });
    pie = {
      title: {
        text: 'Referer of a Website',
        subtext: 'Fake Data',
        left: 'center'
      },
      tooltip: {
        trigger: 'item'
      },
      legend: {
        orient: 'vertical',
        left: 'left'
      },
      series: [{
        name: 'Access From',
        type: 'pie',
        radius: '50%',
        data: [{
          value: 1048,
          name: 'Search Engine'
        }, {
          value: 735,
          name: 'Direct'
        }, {
          value: 580,
          name: 'Email'
        }, {
          value: 484,
          name: 'Union Ads'
        }, {
          value: 300,
          name: 'Video Ads'
        }],
        emphasis: {
          itemStyle: {
            shadowBlur: 10,
            shadowOffsetX: 0,
            shadowColor: 'rgba(0, 0, 0, 0.5)'
          }
        }
      }]
    };
    pie && piChart.setOption(pie);
  }
};
